/* === AlphaClaw Apex Design System === */

@font-face { font-family:'JetBrains Mono'; font-weight:400; font-display:swap; src:url('/shared/fonts/jetbrains-mono-400.woff2') format('woff2'); }
@font-face { font-family:'JetBrains Mono'; font-weight:500; font-display:swap; src:url('/shared/fonts/jetbrains-mono-500.woff2') format('woff2'); }
@font-face { font-family:'JetBrains Mono'; font-weight:600; font-display:swap; src:url('/shared/fonts/jetbrains-mono-600.woff2') format('woff2'); }
@font-face { font-family:'JetBrains Mono'; font-weight:700; font-display:swap; src:url('/shared/fonts/jetbrains-mono-700.woff2') format('woff2'); }

:root {
  --bg: #0d121b;
  --bg-sidebar: #0f141f;
  --bg-content: #0f1521;
  --bg-elevated: #131a27;
  --bg-surface: #131a27;
  --bg-hover: rgba(99, 235, 255, 0.05);
  --bg-active: rgba(99, 235, 255, 0.08);
  --bg-base: #0d121b;

  --glass: rgba(99, 235, 255, 0.02);
  --glass-hover: rgba(99, 235, 255, 0.05);
  --glass-border: rgba(255, 255, 255, 0.06);
  --glass-border-hover: rgba(255, 255, 255, 0.11);

  --border: rgba(255, 255, 255, 0.06);
  --border-strong: rgba(255, 255, 255, 0.11);

  --text: #c9d1d9;
  --text-primary: #c9d1d9;
  --text-bright: #f3f4f6;
  --text-secondary: #8b95a8;
  --text-muted: #6e7681;
  --text-tertiary: #6e7681;
  --text-dim: #424854;

  --accent: #63ebff;
  --accent-dim: rgba(99, 235, 255, 0.4);
  --accent-bg: rgba(99, 235, 255, 0.08);
  --color-primary: #63ebff;
  --color-primary-dim: rgba(99, 235, 255, 0.10);
  --color-accent: #63ebff;
  --color-accent-dim: rgba(99, 235, 255, 0.12);

  --color-success: #86efac;
  --color-warning: #fde047;
  --color-danger: #fca5a5;
  --color-info: #a5f3fc;

  --radius-sm: 6px;
  --radius-md: 10px;
  --radius-lg: 14px;

  --font-sans: 'JetBrains Mono', 'SF Mono', Consolas, monospace;
  --font-mono: 'JetBrains Mono', 'SF Mono', Consolas, monospace;

  --ease-out: cubic-bezier(0.22, 1, 0.36, 1);
  --duration-fast: 150ms;
  --duration-normal: 200ms;

  --nav-width: 56px;
  --nav-width-expanded: 220px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html, body { height: 100%; overflow-x: hidden; }
body {
  font-family: var(--font-sans);
  font-size: 13px;
  line-height: 1.6;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
}

/* Grid texture background (NOT orbs) */
body::before {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.024) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.024) 1px, transparent 1px);
  background-size: 48px 48px;
}
body::after { display: none; }

::selection { background: rgba(99, 235, 255, 0.25); color: #fff; }
::-webkit-scrollbar { width: 5px; height: 5px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: rgba(99, 235, 255, 0.10); border-radius: 999px; }
::-webkit-scrollbar-thumb:hover { background: rgba(99, 235, 255, 0.18); }
* { scrollbar-width: thin; scrollbar-color: rgba(99, 235, 255, 0.10) transparent; }

a { color: var(--accent); text-decoration: none; }
a:hover { text-decoration: underline; }
:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; }

/* Animations */
@keyframes fadeIn { from { opacity: 0; } to { opacity: 1; } }
@keyframes slideUp { from { opacity: 0; transform: translateY(20px); } to { opacity: 1; transform: translateY(0); } }
@keyframes staggerIn { from { opacity: 0; transform: translateY(12px); } to { opacity: 1; transform: translateY(0); } }
@keyframes pulse { 0%,100% { opacity:1; } 50% { opacity:0.3; } }
@keyframes spin { to { transform: rotate(360deg); } }
@keyframes countUp { from { opacity: 0; transform: translateY(8px); } to { opacity: 1; transform: translateY(0); } }

/* Stagger entry system - 50ms per item */
.stagger-item { opacity: 0; transform: translateY(12px); animation: staggerIn 0.4s var(--ease-out) forwards; }
.stagger-item:nth-child(1){animation-delay:0ms}.stagger-item:nth-child(2){animation-delay:50ms}
.stagger-item:nth-child(3){animation-delay:100ms}.stagger-item:nth-child(4){animation-delay:150ms}
.stagger-item:nth-child(5){animation-delay:200ms}.stagger-item:nth-child(6){animation-delay:250ms}
.stagger-item:nth-child(7){animation-delay:300ms}.stagger-item:nth-child(8){animation-delay:350ms}
.stagger-item:nth-child(9){animation-delay:400ms}.stagger-item:nth-child(10){animation-delay:450ms}
.stagger-item:nth-child(11){animation-delay:500ms}.stagger-item:nth-child(12){animation-delay:550ms}

/* Page transition overlay */
#apex-transition{position:fixed;inset:0;z-index:9999;background:var(--bg);display:flex;flex-direction:column;align-items:center;justify-content:center;pointer-events:none;opacity:0;transition:opacity .2s ease}
#apex-transition.active{opacity:1;pointer-events:all}
#apex-transition .t-icon{font-size:64px;opacity:0;transform:scale(.8);transition:all .4s var(--ease-out)}
#apex-transition.show-icon .t-icon{opacity:1;transform:scale(1)}
#apex-transition .t-label{font-size:13px;font-weight:600;color:var(--text-muted);text-transform:uppercase;letter-spacing:3px;margin-top:16px;opacity:0;transition:opacity .3s ease}
#apex-transition.show-label .t-label{opacity:1}

/* Page content entrance */
.page-enter{opacity:0;transform:translateY(20px)}
.page-enter.visible{opacity:1;transform:translateY(0);transition:opacity .4s var(--ease-out),transform .4s var(--ease-out)}

/**
 * AlphaClaw Apex Navigation — Global Sidebar Component
 * ES Module: import { renderNav } from '/shared/nav.js';
 */

const NAV_GROUPS = [
  {
    label: 'Core',
    items: [
      { id: 'dashboard',   icon: '⬡',  label: 'Dashboard',   path: '/dashboard/' },
      { id: 'chat',        icon: '💬', label: 'Chat',        path: '/chat/' },
      { id: 'roundtable',  icon: '🔮', label: 'Roundtable',  path: '/roundtable/' },
      { id: 'deep-think',  icon: '🧠', label: 'Deep Think',  path: '/deep-think/' },
      { id: 'vault',       icon: '🔐', label: 'Vault',       path: '/vault/' },
    ]
  },
  {
    label: 'Operations',
    items: [
      { id: 'mission',     icon: '📡', label: 'Mission Control', path: '/mission/' },
      { id: 'monitor',     icon: '📊', label: 'Monitor',     path: '/monitor/' },
      { id: 'analytics',   icon: '📈', label: 'Analytics',   path: '/analytics/' },
      { id: 'tasks',       icon: '✅', label: 'Tasks',       path: '/tasks/' },
      { id: 'files',       icon: '📁', label: 'Files',       path: '/files/' },
    ]
  },
  {
    label: 'Business',
    items: [
      { id: 'leads',       icon: '🎯', label: 'Leads',       path: '/leads/' },
      { id: 'icat',        icon: '🐱', label: 'ICat',        path: '/icat/' },
      { id: 'pipeline',    icon: '🔄', label: 'Pipeline',    path: '/pipeline/' },
      { id: 'broadcast',   icon: '📢', label: 'Broadcast',   path: '/broadcast/' },
    ]
  },
  {
    label: 'System',
    items: [
      { id: 'users',          icon: '👥', label: 'Users',          path: '/users/' },
      { id: 'settings',       icon: '⚙️', label: 'Settings',       path: '/settings/' },
      { id: 'reports',        icon: '📋', label: 'Reports',        path: '/reports/' },
      { id: 'notifications',  icon: '🔔', label: 'Notifications',  path: '/notifications/' },
    ]
  }
];

const NAV_CSS = `
.apex-nav {
  position: fixed;
  left: 0;
  top: 0;
  bottom: 0;
  width: var(--nav-width, 56px);
  background: var(--bg-sidebar, #0f141f);
  border-right: 1px solid var(--border, rgba(255,255,255,0.06));
  display: flex;
  flex-direction: column;
  z-index: 40;
  transition: width 0.25s var(--ease-out, cubic-bezier(0.22,1,0.36,1));
  overflow: hidden;
  font-family: var(--font-sans, 'JetBrains Mono', monospace);
}
.apex-nav:hover,
.apex-nav.expanded {
  width: var(--nav-width-expanded, 220px);
}

/* Logo */
.apex-nav-logo {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 14px 16px 10px;
  border-bottom: 1px solid var(--border, rgba(255,255,255,0.06));
  text-decoration: none;
  flex-shrink: 0;
}
.apex-nav-logo-icon {
  font-size: 18px;
  flex-shrink: 0;
  width: 24px;
  text-align: center;
}
.apex-nav-logo-text {
  font-size: 13px;
  font-weight: 700;
  letter-spacing: 2px;
  color: var(--accent, #63ebff);
  white-space: nowrap;
  opacity: 0;
  transition: opacity 0.2s;
}
.apex-nav:hover .apex-nav-logo-text,
.apex-nav.expanded .apex-nav-logo-text {
  opacity: 1;
}

/* Scroll area */
.apex-nav-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: 8px 6px;
  scrollbar-width: none;
}
.apex-nav-scroll::-webkit-scrollbar { width: 0; }

/* Group labels */
.apex-nav-group-label {
  font-size: 9px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 1.5px;
  color: var(--text-dim, #424854);
  padding: 12px 10px 4px;
  white-space: nowrap;
  opacity: 0;
  transition: opacity 0.15s;
}
.apex-nav:hover .apex-nav-group-label,
.apex-nav.expanded .apex-nav-group-label {
  opacity: 1;
}

/* Nav items */
.apex-nav-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 12px;
  border-radius: var(--radius-md, 10px);
  cursor: pointer;
  text-decoration: none;
  color: var(--text-muted, #6e7681);
  font-size: 12px;
  font-weight: 500;
  transition: all 0.15s;
  margin-bottom: 2px;
  white-space: nowrap;
  border-left: 3px solid transparent;
}
.apex-nav-item:hover {
  background: var(--bg-hover, rgba(99,235,255,0.05));
  color: var(--text-primary, #c9d1d9);
  text-decoration: none;
}
.apex-nav-item.active {
  border-left-color: var(--accent, #63ebff);
  background: var(--bg-active, rgba(99,235,255,0.08));
  color: var(--accent, #63ebff);
}
.apex-nav-item-icon {
  width: 24px;
  flex-shrink: 0;
  text-align: center;
  font-size: 16px;
  line-height: 1;
}
.apex-nav-item-label {
  opacity: 0;
  transition: opacity 0.15s;
  overflow: hidden;
  text-overflow: ellipsis;
}
.apex-nav:hover .apex-nav-item-label,
.apex-nav.expanded .apex-nav-item-label {
  opacity: 1;
}

/* Footer */
.apex-nav-footer {
  padding: 10px 16px;
  border-top: 1px solid var(--border, rgba(255,255,255,0.06));
  flex-shrink: 0;
  display: flex;
  align-items: center;
  gap: 8px;
}
.apex-nav-footer-text {
  font-size: 9px;
  color: var(--text-dim, #424854);
  letter-spacing: 0.5px;
  white-space: nowrap;
  opacity: 0;
  transition: opacity 0.15s;
}
.apex-nav:hover .apex-nav-footer-text,
.apex-nav.expanded .apex-nav-footer-text {
  opacity: 1;
}

/* Mobile: hamburger overlay */
.apex-nav-hamburger {
  display: none;
  position: fixed;
  top: 8px;
  left: 8px;
  z-index: 41;
  width: 36px;
  height: 36px;
  border: 1px solid var(--border, rgba(255,255,255,0.06));
  border-radius: var(--radius-md, 10px);
  background: var(--bg-sidebar, #0f141f);
  color: var(--text-secondary, #8b95a8);
  font-size: 18px;
  cursor: pointer;
  align-items: center;
  justify-content: center;
}
.apex-nav-overlay {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.6);
  z-index: 39;
}
.apex-nav-overlay.show { display: block; }

@media (max-width: 768px) {
  .apex-nav {
    transform: translateX(-100%);
    width: var(--nav-width-expanded, 220px);
    box-shadow: 4px 0 24px rgba(0,0,0,0.5);
  }
  .apex-nav.mobile-open {
    transform: translateX(0);
  }
  .apex-nav:hover { width: var(--nav-width-expanded, 220px); }
  .apex-nav .apex-nav-logo-text,
  .apex-nav .apex-nav-group-label,
  .apex-nav .apex-nav-item-label,
  .apex-nav .apex-nav-footer-text {
    opacity: 1;
  }
  .apex-nav-hamburger { display: flex; }
  .page-main,
  .page-layout > :not(.apex-nav):not(.apex-nav-overlay):not(.apex-nav-hamburger) {
    margin-left: 0 !important;
  }
}
@media (min-width: 769px) {
  body.has-nav {
    padding-left: var(--nav-width, 56px);
  }
  .page-main,
  .page-layout > :not(.apex-nav):not(.apex-nav-overlay):not(.apex-nav-hamburger) {
    margin-left: 0 !important;
  }
}
@media (max-width: 768px) {
  body.has-nav {
    padding-left: 0 !important;
  }
}
`;

function handleNavClick(e, url, icon, label) {
  // Don't intercept if modifier keys held (open in new tab etc)
  if (e.metaKey || e.ctrlKey || e.shiftKey) return;
  e.preventDefault();
  if (window.__apexNavTo) {
    window.__apexNavTo(url, icon, label);
  } else {
    window.location.href = url;
  }
}

export function renderNav(activePage) {
  // Inject CSS
  if (!document.getElementById('apex-nav-styles')) {
    const style = document.createElement('style');
    style.id = 'apex-nav-styles';
    style.textContent = NAV_CSS;
    document.head.appendChild(style);
  }

  // Build nav HTML
  const nav = document.createElement('nav');
  nav.className = 'apex-nav';
  nav.id = 'apexNav';

  let html = `<a class="apex-nav-logo" href="/dashboard/">
    <span class="apex-nav-logo-icon">✦</span>
    <span class="apex-nav-logo-text">MAGI</span>
  </a>
  <div class="apex-nav-scroll">`;

  for (const group of NAV_GROUPS) {
    html += `<div class="apex-nav-group-label">${group.label}</div>`;
    for (const item of group.items) {
      const isActive = activePage === item.id ? ' active' : '';
      html += `<a class="apex-nav-item${isActive}" href="${item.path}" data-nav-icon="${item.icon}" data-nav-label="${item.label}">
        <span class="apex-nav-item-icon">${item.icon}</span>
        <span class="apex-nav-item-label">${item.label}</span>
      </a>`;
    }
  }

  html += `</div>
  <div class="apex-nav-footer">
    <span style="font-size:14px;">✦</span>
    <span class="apex-nav-footer-text">MAGI v2.0</span>
  </div>`;

  nav.innerHTML = html;

  // Attach click handlers for page transitions
  nav.querySelectorAll('.apex-nav-item').forEach(item => {
    item.addEventListener('click', (e) => {
      handleNavClick(e, item.getAttribute('href'), item.dataset.navIcon, item.dataset.navLabel);
    });
  });

  // Logo also uses transitions
  const logoLink = nav.querySelector('.apex-nav-logo');
  if (logoLink) {
    logoLink.addEventListener('click', (e) => {
      handleNavClick(e, '/dashboard/', '⬡', 'Dashboard');
    });
  }

  // Create hamburger button
  const burger = document.createElement('button');
  burger.className = 'apex-nav-hamburger';
  burger.id = 'apexNavBurger';
  burger.innerHTML = '☰';
  burger.setAttribute('aria-label', 'Toggle navigation');

  // Create overlay
  const overlay = document.createElement('div');
  overlay.className = 'apex-nav-overlay';
  overlay.id = 'apexNavOverlay';

  // Inject into DOM
  const target = document.getElementById('nav');
  if (target) {
    target.appendChild(nav);
    target.appendChild(burger);
    target.appendChild(overlay);
  } else {
    document.body.prepend(overlay);
    document.body.prepend(nav);
    document.body.prepend(burger);
  }

  // Mobile toggle
  function toggleMobileNav() {
    const open = nav.classList.toggle('mobile-open');
    overlay.classList.toggle('show', open);
  }
  burger.addEventListener('click', toggleMobileNav);
  overlay.addEventListener('click', toggleMobileNav);

  // Add body class for padding
  document.body.classList.add('has-nav');

  // ─── Notification badge in sidebar ───
  _updateNavNotifBadge(nav);

  return nav;
}

// Fetch unread count and inject badge next to 🔔 Notifications nav item
async function _updateNavNotifBadge(navEl) {
  try {
    const token = localStorage.getItem('magi_token');
    if (!token) return;
    const res = await fetch('/api/notifications', {
      headers: { Authorization: `Bearer ${token}` }
    });
    if (!res.ok) return;
    const data = await res.json();
    const items = data.items || data.notifications || [];
    const unread = data.unread != null ? data.unread : items.filter(n => !n.read).length;
    if (unread <= 0) return;

    const notifLink = navEl.querySelector('.apex-nav-item[href="/notifications/"]');
    if (!notifLink) return;

    const badge = document.createElement('span');
    badge.className = 'nav-notif-badge';
    badge.textContent = unread > 99 ? '99+' : unread;
    badge.style.cssText = 'background:#f87171;color:#fff;font-size:9px;font-weight:700;min-width:16px;height:16px;border-radius:99px;display:inline-flex;align-items:center;justify-content:center;padding:0 4px;margin-left:auto;font-family:var(--font-mono,monospace);';
    notifLink.appendChild(badge);
  } catch {
    // Silent fail — badge is a bonus feature
  }
}

